export interface OddsBookQuote {
  key: string;
  title: string;
  spread: string;
}

export interface OddsBooksGame {
  awayTeam: string;
  homeTeam: string;
  closingSpread: string;
  books: OddsBookQuote[];
}

export const oddsBooksGames: OddsBooksGame[] = [];

/** Lookup multi-book quotes for a matchup (either order). */
export function booksForMatchup(away: string, home: string): OddsBooksGame | undefined {
  const a = away.toUpperCase();
  const h = home.toUpperCase();
  return oddsBooksGames.find(
    (g) =>
      (g.awayTeam.toUpperCase() === a && g.homeTeam.toUpperCase() === h) ||
      (g.awayTeam.toUpperCase() === h && g.homeTeam.toUpperCase() === a),
  );
}

/** Count how many books share the modal favorite-side string. */
export function consensusSummary(game: OddsBooksGame): { label: string; agree: number; total: number } | null {
  if (!game.books.length) return null;
  const counts = new Map<string, number>();
  for (const b of game.books) {
    counts.set(b.spread, (counts.get(b.spread) ?? 0) + 1);
  }
  let best = game.books[0].spread;
  let n = 0;
  for (const [spread, c] of counts) {
    if (c > n) {
      n = c;
      best = spread;
    }
  }
  return { label: best, agree: n, total: game.books.length };
}
